import json, subprocess, sys
repo='xbmc/kodiai'
pr='134'
cmds={
  'reviews':['gh','api',f'repos/{repo}/pulls/{pr}/reviews','--paginate'],
  'review_comments':['gh','api',f'repos/{repo}/pulls/{pr}/comments','--paginate'],
  'issue_comments':['gh','api',f'repos/{repo}/issues/{pr}/comments','--paginate'],
}
for name, cmd in cmds.items():
    try:
        out=subprocess.check_output(cmd, text=True, stderr=subprocess.STDOUT, timeout=60)
        data=json.loads(out or '[]')
    except subprocess.CalledProcessError as e:
        print(f'{name}: ERROR exit={e.returncode} output={e.output[:500]}')
        continue
    except Exception as e:
        print(f'{name}: ERROR {type(e).__name__}: {e}')
        continue
    print(f'== {name}: {len(data)} ==')
    if name=='reviews':
        for r in data:
            body=(r.get('body') or '')
            has_marker='kodiai-review-output' in body or 'mention-format-suggestions' in body
            print(json.dumps({
                'id': r.get('id'), 'user': (r.get('user') or {}).get('login'), 'state': r.get('state'),
                'submitted_at': r.get('submitted_at'), 'html_url': r.get('html_url'),
                'has_marker': has_marker,
                'body_excerpt': body[:240].replace('\n',' ')
            }))
    elif name=='review_comments':
        for c in data:
            body=(c.get('body') or '')
            has_suggestion='```suggestion' in body
            has_marker='kodiai-review-output' in body or 'mention-format-suggestions' in body
            print(json.dumps({
                'id': c.get('id'), 'pull_request_review_id': c.get('pull_request_review_id'),
                'user': (c.get('user') or {}).get('login'), 'created_at': c.get('created_at'),
                'html_url': c.get('html_url'), 'has_suggestion': has_suggestion, 'has_marker': has_marker,
                'body_excerpt': body[:240].replace('\n',' ')
            }))
    else:
        for c in data[-8:]:
            body=(c.get('body') or '')
            has_formatter='mention-format-suggestions' in body or '@kodiai format suggestions' in body
            print(json.dumps({
                'id': c.get('id'), 'user': (c.get('user') or {}).get('login'), 'created_at': c.get('created_at'),
                'html_url': c.get('html_url'), 'has_formatter_text': has_formatter,
                'body_excerpt': body[:240].replace('\n',' ')
            }))
